  'Mệnh':      { tamHop: ['Tài Bạch','Quan Lộc'],       xung: 'Thiên Di' },
  'Huynh Đệ':  { tamHop: ['Điền Trạch','Tật Ách'],      xung: 'Nô Bộc' },
