  'Nô Bộc':    { tamHop: ['Phụ Mẫu','Tử Tức'],          xung: 'Huynh Đệ' },
  'Quan Lộc':  { tamHop: ['Mệnh','Tài Bạch'],            xung: 'Phu Thê' },
  'Điền Trạch':{ tamHop: ['Huynh Đệ','Tật Ách'],        xung: 'Tử Tức' },
